parameters.jsCode:
let raw = $input.first().json.text || $input.first().json.message?.content || '';
raw = raw.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();

try {
  const parsed = JSON.parse(raw);
  return [{
    json: {
      ...$input.first().json,
      email_subject: parsed.subject || 'Partnership Opportunity — RinglyAI',
      email_body: parsed.body || raw,
    }
  }];
} catch (e) {
  return [{
    json: {
      ...$input.first().json,
      email_subject: 'Partnership Opportunity — RinglyAI x ' + ($input.first().json['Name'] || 'You'),
      email_body: raw,
    }
  }];
}
